## 1. Conflict Resolution Strategy

### Operational Transformation (OT)
The classic approach used by Google Docs.

```python
class Operation:
    def __init__(self, type, position, content, user_id, timestamp, doc_version):
        self.type = type          # INSERT | DELETE | RETAIN
        self.position = position
        self.content = content
        self.user_id = user_id
        self.timestamp = timestamp
        self.doc_version = doc_version

def transform(op1, op2):
    """
    Transform op1 against op2 so both can be applied
    and reach the same document state.
    """
    if op1.type == "INSERT" and op2.type == "INSERT":
        if op2.position <= op1.position:
            # op2 shifts op1's position forward
            return Operation(
                op1.type,
                op1.position + len(op2.content),
                op1.content,
                op1.user_id,
                op1.timestamp,
                op1.doc_version
            )

    if op1.type == "INSERT" and op2.type == "DELETE":
        if op2.position < op1.position:
            return Operation(
                op1.type,
                op1.position - len(op2.content),
                op1.content,
                op1.user_id,
                op1.timestamp,
                op1.doc_version
            )

    if op1.type == "DELETE" and op2.type == "INSERT":
        if op2.position <= op1.position:
            return Operation(
                op1.type,
                op1.position + len(op2.content),
                op1.content,
                op1.user_id,
                op1.timestamp,
                op1.doc_version
            )

    if op1.type == "DELETE" and op2.type == "DELETE":
        if op2.position < op1.position:
            return Operation(
                op1.type,
                op1.position - len(op2.content),
                op1.content,
                op1.user_id,
                op1.timestamp,
                op1.doc_version
            )
        elif op2.position == op1.position:
            # Same deletion - make op1 a no-op
            return None

    return op1  # No transformation needed
```

### Alternative: CRDTs (Conflict-free Replicated Data Types)
Better for distributed systems without a central server.

```python
class CRDTDocument:
    """
    Each character has a unique ID and tombstone for deletions.
    Uses a logical clock for ordering.
    """
    def __init__(self):
        self.characters = []  # List of (char_id, char, is_deleted)
        self.clock = LogicalClock()

    def insert(self, position, char, site_id):
        char_id = (self.clock.tick(), site_id)
        # Find the actual position considering tombstones
        actual_pos = self._find_actual_position(position)
        self.characters.insert(actual_pos, {
            'id': char_id,
            'char': char,
            'deleted': False,
            'prev_id': self._get_id_at(actual_pos - 1),
            'next_id': self._get_id_at(actual_pos)
        })
        return char_id

    def delete(self, char_id):
        # Tombstone deletion - never remove, just mark deleted
        for char in self.characters:
            if char['id'] == char_id:
                char['deleted'] = True
                break

    def get_text(self):
        return ''.join(
            c['char'] for c in self.characters 
            if not c['deleted']
        )

    def merge(self, remote_operation):
        """Merge is always safe - no conflicts possible"""
        if remote_operation.type == 'INSERT':
            self._integrate_insert(remote_operation)
        elif remote_operation.type == 'DELETE':
            self.delete(remote_operation.char_id)
