## 2. Client Architecture

```javascript
class DocumentEditor {
    constructor(docId, userId) {
        this.docId = docId;
        this.userId = userId;
        this.localVersion = 0;
        this.pendingOps = [];       // Sent but unacknowledged
        this.bufferedOps = [];      // Not yet sent (offline)
        this.ws = null;
        this.isOnline = false;
    }

    connect() {
        this.ws = new WebSocket(`wss://collab.service/doc/${this.docId}`);

        this.ws.onopen = () => {
            this.isOnline = true;
            this.syncPendingOperations();
        };

        this.ws.onmessage = (event) => {
            const message = JSON.parse(event.data);
            this.handleServerMessage(message);
        };

        this.ws.onclose = () => {
            this.isOnline = false;
            this.scheduleReconnect();
        };
    }

    applyLocalEdit(operation) {
        // 1. Apply immediately to local document (optimistic update)
        this.applyToLocalDoc(operation);

        // 2. Transform against pending ops
        let transformedOp = operation;
        for (const pending of this.pendingOps) {
            transformedOp = transform(transformedOp, pending);
        }

        // 3. Queue for sending
        transformedOp.version = this.localVersion;
        this.pendingOps.push(transformedOp);

        // 4. Send if online
        if (this.isOnline) {
            this.sendOperation(transformedOp);
        } else {
            this.bufferedOps.push(transformedOp);
        }
    }

    handleServerMessage(message) {
        switch(message.type) {
            case 'ACK':
                // Server confirmed our operation
                this.pendingOps = this.pendingOps.filter(
                    op => op.id !== message.operationId
                );
                this.localVersion = message.newVersion;
                break;

            case 'REMOTE_OP':
                // Another user's operation
                this.applyRemoteOperation(message.operation);
                break;

            case 'SYNC':
                // Full document sync (on reconnect)
                this.fullSync(message.document, message.version);
                break;
        }
    }

    applyRemoteOperation(remoteOp) {
        // Transform remote op against all pending local ops
        let transformedRemoteOp = remoteOp;

        for (const pending of this.pendingOps) {
            [transformedRemoteOp, pending] = transformBoth(
                transformedRemoteOp, 
                pending
            );
        }

        // Apply to local document
        this.applyToLocalDoc(transformedRemoteOp);
        this.localVersion = remoteOp.version + 1;
    }

    scheduleReconnect() {
        // Exponential backoff
        const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), 30000);
        setTimeout(() => this.connect(), delay);
        this.reconnectAttempts++;
    }
}
```

