## 5. Presence & Awareness Features

```javascript
class PresenceManager {
    constructor(editor) {
        this.editor = editor;
        this.remoteUsers = new Map();
        this.cursorDecorations = new Map();
    }

    updateLocalCursor(position) {
        // Throttle cursor updates (max 10/sec)
        this.throttledSend({
            type: 'CURSOR',
            position: position,
            selection: this.editor.getSelection()
        });
    }

    handleRemoteCursor(userId, position, color, name) {
        // Render cursor with user's color and name
        const decoration = {
            position: position,
            color: color,
            label: name,
            blinkAnimation: true
        };

        this.cursorDecorations.set(userId, decoration);
        this.editor.renderCursor(decoration);

        // Auto-hide after inactivity
        this.resetInactivityTimer(userId);
    }

    handleUserJoined(user) {
        this.remoteUsers.set(user.id, user);
        this.showNotification(`${user.name} joined`);
        this.updateCollaboratorsList();
    }

    handleUserLeft(userId) {
        this.remoteUsers.delete(userId);
        this.cursorDecorations.delete(userId);
        this.editor.removeCursor(userId);
        this.updateCollaboratorsList();
    }
}
