## 7. Offline Support

```javascript
class OfflineManager {
    constructor() {
        this.db = new IndexedDB('collab_offline');
        this.syncQueue = [];
    }

    async saveOfflineOperation(operation) {
        await this.db.put('pending_ops', {
            ...operation,
            savedAt: Date.now()
        });
    }

    async syncOnReconnect(serverVersion) {
        const pendingOps = await this.db.getAll('pending_ops');

        if (pendingOps.length === 0) return;

        // Request full sync if too many missed operations
        if (serverVersion - this.lastKnownVersion > SYNC_THRESHOLD) {
            await this.requestFullSync();
        } else {
            // Replay pending operations
            for (const op of pendingOps) {
                await this.sendOperation(op);
            }
        }

        await this.db.clear('pending_ops');
    }
}
```

