## 8. Performance Optimizations

```python
class DocumentOptimizer:

    def compress_operations(self, ops):
        """
        Merge consecutive operations from same user.
        e.g., typing 'hello' = 5 ops -> 1 op
        """
        compressed = []
        for op in ops:
            if (compressed and 
                compressed[-1].user_id == op.user_id and
                compressed[-1].type == op.type == 'INSERT' and
                compressed[-1].position + len(compressed[-1].content) == op.position and
                op.timestamp - compressed[-1].timestamp < 500):  # 500ms window
                compressed[-1].content += op.content
            else:
                compressed.append(op)
        return compressed

    async def create_snapshot(self, doc_id, version):
        """
        Periodically snapshot to avoid replaying all history.
        """
        ops = await self.get_all_ops(doc_id)
        document = self.replay_operations(ops)

        await self.db.save_snapshot({
            'doc_id': doc_id,
            'version': version,
            'content': document,
            'created_at': datetime.now()
        })

    def delta_sync(self, client_version, current_version):
        """
        Only send operations since client's last known version.
        """
        return self.get_ops_between(client_version, current_version)
